const AXIS_MAX = 1000;
const AXIS_WIDTH = 520; // pixels

function msToX(ms) {
  return (ms / AXIS_MAX) * AXIS_WIDTH;
}

function buildScaleDiagram(scaleKey, scale) {
  const ticks = scale.values.map(v => {
    const x = msToX(v);
    const label = scale.labels[v] || `${v}ms`;
    return `
      <g>
        <line x1="${x}" y1="0" x2="${x}" y2="20" stroke="${scale.color}" stroke-width="2" />
        <text x="${x}" y="32" text-anchor="middle" font-size="9" fill="${scale.color}" font-family="monospace">${v}</text>
        <text x="${x}" y="44" text-anchor="middle" font-size="8" fill="#888">${label}</text>
      </g>
    `;
  }).join('');

  return `
    <div style="margin-bottom:24px;">
      <div style="font-size:13px; font-weight:700; color:${scale.color}; margin-bottom:4px;">${scale.name}</div>
      <div style="font-size:11px; color:#888; margin-bottom:8px; font-style:italic;">${scale.naming}</div>
      <svg width="${AXIS_WIDTH + 20}" height="54" overflow="visible" style="display:block;">
        <line x1="0" y1="0" x2="${AXIS_WIDTH}" y2="0" stroke="#e0e0e0" stroke-width="2" />
        ${ticks}
      </svg>
      <div style="display:flex; justify-content:space-between; width:${AXIS_WIDTH}px; font-size:9px; color:#ccc; margin-top:2px;">
        <span>0ms</span><span>500ms</span><span>1000ms</span>
      </div>
    </div>
  `;
}

